head.script:
// scwin.MSG_CM_CRM_001 = "저장하시겠습니까?" 
scwin.MSG_CM_CRM_002 = "변경된 내용이 있습니다. 저장하시겠습니까?"

scwin.MSG_CM_ERR_001 = "그룹코드는 필수 입력사항입니다. 입력하세요."
scwin.MSG_CM_ERR_002 = "그룹코드는 4자리 입니다. 자리수를 맞혀주세요."
scwin.MSG_CM_ERR_003 = "그룹명은 필수 입력사항입니다. 입력하세요."
scwin.MSG_CM_ERR_004 = "그룹코드는 중복된 값을 입력할 수 없습니다. 다시 입력하세요."
scwin.MSG_CM_ERR_005 = "변경된 사항이 없습니다."
scwin.MSG_CM_ERR_006 = "조회된 데이터가 없습니다."
scwin.MSG_CM_ERR_007 = "권한그룹을 먼저 조회하세요."
scwin.MSG_CM_ERR_008 = "프로그램 조회후 사용하세요."

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.onpageload = async function() {
    $c.gus.cfDisableKeyData();
    $p.setTimeout(function() {
        ed_searchPrivGrp.focus();
    }, {"delay":200});
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() { 
    scwin.init();
    if( $p.getAllParameter().paramData.menuInfo.menuId.indexOf("n") > -1){
        rd_debis.setSelectedIndex(1);
        rd_debis.setDisabled(true);
    }
};

scwin.init = function() {
    let vparam1 = "";
    if(rd_debis.getValue() == "N") {
        vparam1 = "Ncall";
    }

    const codeOptions1 = [
        { method: "getLuxeComboData"
        , param1: vparam1+"ProgramEBC"
        , param2: "retrieveSysCdList"
        , param3: [""]
        , compID: "lc_sysCd" 
        },
    ];
    $c.data.setGauceUtil(codeOptions1);

    // rd_debis.setSelectedIndex(0);
    lc_privGrpSearch.setSelectedIndex(0);
    ed_searchPrivGrp.setValue("");
    lc_programSearch.setSelectedIndex(0);
    ed_searchProgram.setValue("");
    lc_pgmCond.setSelectedIndex(0);
    ed_pgmName.setValue("");

    ds_415List.setJSON([]);
    ds_451List.setJSON([]);
    ds_411List.setJSON([]);

    gr_415List_spanTotal.setLabel(0);
    gr_451List_spanTotal.setLabel(0);
    gr_411List_spanTotal.setLabel(0);
};

/**
 * UDC 셋팅이 이후..
 */
scwin.onUdcCompleted = function() {
};    

