//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function(idx) {
    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
	if(idx == "1"){
        //프로그램
        var arrJson = { sysCls:lc_sysCd.getValue()
                      , programLupCond:lc_programSearch.getValue()
                      , qryCntn:ed_searchProgram.getValue()
                      , grpCls:"00"
                      };
        sbm_411List.action = "/"+debis+"cm.bc.comnmgnt.programmgnt.RetrieveProgramListCMD.do";
        $c.sbm.execute(sbm_411List, arrJson);
	}else{
        //권한그룹
        var arrJson = { qryCond:lc_privGrpSearch.getValue()
                      , qryCntn:ed_searchPrivGrp.getValue()
                      };
        sbm_415List.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.RetrievePrivilegeGroupListCMD.do";
        $c.sbm.execute(sbm_415List, arrJson);
	}
};

//-------------------------------------------------------------------------
// function name : f_MainRetrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_MainRetrieve = function( privGrpId ) {
    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
    let arrJson = { privilegeGroupId:privGrpId };
    sbm_451List.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.RetrievePrivilegeGroupEachProgramPrivilegeListCMD.do";
    $c.sbm.execute(sbm_451List, arrJson);
};

//-------------------------------------------------------------------------
// function name : f_Create
// function desc : 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    if( ds_415List.getModifiedIndex().length > 0
        || ds_451List.getModifiedIndex().length > 0 )
    {
        //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
        for(var i=0; i<ds_415List.getRowCount(); i++) {
            var rowJson = ds_415List.getRowJSON(i);

            if(ds_415List.rowStatus=="C" || ds_415List.rowStatus=="U"){
                if(rowJson.privGrpId.trim()==''){
                    $c.win.alert(scwin.MSG_CM_ERR_001);
                    return;
                }else if(rowJson.privGrpId.trim().length!=4){
                    $c.win.alert(scwin.MSG_CM_ERR_002);
                    return;
                }else if(rowJson.privGrpNm.trim()==''){
                    $c.win.alert(scwin.MSG_CM_ERR_003);
                    return;
                }
                for(var j=0; j<ds_415List.getRowCount(); j++) {
                    if(j!=i){
                        if( rowJson.privGrpId.trim() == ds_415List.getCellData( j, "privGrpId" ).trim() ){
                            $c.win.alert(scwin.MSG_CM_ERR_004);
                            return;
                        }
                    }	
                }
            }
        }
        $c.sbm.execute(sbm_save);
    }

    $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete]);
    let rowIndex = ds_415List.insertRow();
    gr_415List.setFocusedCell(rowIndex, "privGrpId", false);
    gr_415List.setReadOnly("column", "privGrpNm", false);
    ds_451List.setJSON([]);

};

//-------------------------------------------------------------------------
// function name : f_Update
// function desc : 수정
//-------------------------------------------------------------------------
scwin.f_Update = function() {
    gr_415List.setReadOnly("column", "privGrpNm", false);    
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete]);
};

//-------------------------------------------------------------------------
// function name : f_Cancel
// function desc : 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function() {
    ds_415List.undoAll();
    ds_451List.undoAll();
    // $c.data.undoRow(ds_415List);
    // $c.data.undoRow(ds_451List);
    gr_415List.setReadOnly("column", "privGrpNm", true);
    $c.gus.cfDisableBtn([""]);
};

