//-------------------------------------------------------------------------
// function name : f_UndoAll
// function desc : 취소
//-------------------------------------------------------------------------
scwin.f_UndoAll = function() {
    console.log("===============f_UndoAll===");
    ds_451List.undoAll();
    ds_411List.undoAll();
    // $c.data.undoRow(ds_451List);
    // $c.data.undoRow(ds_411List);
	var pgmCnt  = ds_411List.getRowCount();
	var privCnt = ds_451List.getRowCount();

    scwin.fn_undo(ds_451List);

    for(var i=0; i<privCnt; i++) {
        var rowJson = ds_451List.getRowJSON(i);
        for(var j=0; j<pgmCnt; j++) {
            var rowJsonJ = ds_411List.getRowJSON(j);
            if( rowJson.pgmId == rowJsonJ.pgmId ){
                ds_411List.removeRow(j)
                break;
            }else{
				continue;
			}
        }
	}//for

    for(var x=0; x<ds_411OrgList.getRowCount(); x++) {
        var tot411chk = false;
        var rowJsonx = ds_411OrgList.getRowJSON(x);
        for(var y=0; y<ds_411List.getRowCount(); y++) {
            var rowJsony = ds_411List.getRowJSON(y);
            if( rowJsonx.pgmId == rowJsony.pgmId ){
                tot411chk = true;
			}
        }
        if(!tot411chk) {
            ds_411List.insertJSON(ds_411List.getRowCount(), [rowJsonx]);
        }
	}//for
    ds_411List.modifyAllStatus("R");
};

scwin.fn_undo = function (paramObj) {
    for( var idx = paramObj.getRowCount()-1; idx>-1 ;idx--){
        var stat = paramObj.getRowStatus(idx);
        if(stat == 'C') {
            paramObj.removeRow(idx);
        } else if(stat == 'U') {
            paramObj.undoRow(idx);
        }
    }
};


//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {

    let ds_415ListModi = ds_415List.getModifiedJSON();
    let ds_451ListModi = ds_451List.getModifiedJSON();

	//변경한 데이터가 있는지 체크한다. 
    if( (ds_415ListModi.length == 0) && (ds_451ListModi.length == 0) ) {
        $c.win.alert(scwin.MSG_CM_ERR_005);
        return;
    }

    //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
    for(let i=0; i<ds_415List.getRowCount(); i++) {
        let rowJson = ds_415List.getRowJSON(i);
      	if(rowJson.rowStatus=="C" || rowJson.rowStatus=="U"){
      		if(rowJson.privGrpId.trim()==''){
      			$c.win.alert(scwin.MSG_CM_ERR_001);
      			return;
      		}else if(rowJson.privGrpId.trim().length!=4){
      			$c.win.alert(scwin.MSG_CM_ERR_002);
      			return;
            }else if(rowJson.privGrpNm.trim()==''){
      			$c.win.alert(scwin.MSG_CM_ERR_003);
      			return;
      		}
            for(let j=0; j<ds_415List.getRowCount(); j++) {
	   			if(j!=i){
		   			if( rowJson.privGrpId.trim() == ds_415List.getCellData( j, "privGrpId" ).trim() ){
		   				$c.win.alert(scwin.MSG_CM_ERR_004);
		   				return;
		   			}
		   		}	
	   		}
      	}
    }

    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
    sbm_save.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.SavePrivilegeGroupCMD.do";
    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
    if (confirmResult) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// function name : f_Delete
// function desc : 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = function() {
    var rowIndex = gr_415List.getFocusedRowIndex();
    ds_415List.deleteRow(rowIndex);

	$c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete, btn_DeleteAll]);
    //btn_UndoAll 수정예정

    for (var i=0;i<ds_451List.getRowCount();i++) {
        ds_451List.deleteRow(i);
    }
};

//-------------------------------------------------------------------------
// function name : f_DeleteAll
// function desc : 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteAll = function() {
    scwin.fn_undo(ds_451List);
    for (var i=0;i<ds_451List.getRowCount();i++) {
        var rowJson = ds_451List.getRowJSON(i);
        if( rowJson.rowStatus == "C" ) {
            ds_451List.removeRow(i);
        } else {
            ds_451List.deleteRow(i);
        }
    }
};

//-------------------------------------------------------------------------
// function name : f_LMove
// function desc : 좌이동
//-------------------------------------------------------------------------
scwin.f_LMove = function() {
	var vPrivGrpCount = ds_415List.getRowCount(); 
	var pgmCnt  = ds_411List.getRowCount();
	var privCnt = ds_451List.getRowCount();
	var privGrpId = ds_415List.getCellData(ds_415List.getRowPosition(), "privGrpId");

	if(vPrivGrpCount<1 && privCnt<1){
		$c.win.alert(scwin.MSG_CM_ERR_007);
		return;
	}else if(pgmCnt<1){
		$c.win.alert(scwin.MSG_CM_ERR_008);
		return;
	}else{
		for(var i=0; i<pgmCnt; i++){
			var chkYn = ds_411List.getCellData(i, "chk");
			var pgmId = ds_411List.getCellData(i, "pgmId");
			var pgmNm = ds_411List.getCellData(i, "pgmNm");
			if(chkYn == "1"){
                // alert(i);
				var addFlag = "A";
				for(var j=1; j<=privCnt; j++){
					var privPgmId = ds_451List.getCellData(j, "pgmId");
					if(pgmId == privPgmId){
						addFlag = "N";
						break;
					}else{
						continue;
					}
				}

				if(addFlag == "A"){

                    let rowIndex = ds_451List.insertRow();

					ds_451List.setCellData(rowIndex, "privGrpId", privGrpId);
					ds_451List.setCellData(rowIndex, "pgmId", pgmId); 
					ds_451List.setCellData(rowIndex, "pgmNm", pgmNm); 
					ds_451List.setCellData(rowIndex, "insYn", 0); 
					ds_451List.setCellData(rowIndex, "qryYn", 1); 					
					ds_451List.setCellData(rowIndex, "modYn", 0); 
					ds_451List.setCellData(rowIndex, "delYn", 0); 
					ds_451List.setCellData(rowIndex, "prtnYn", 1);					
					ds_451List.setCellData(rowIndex, "xlsDwnldYn", 1); 					 
                    gr_451List.setFocusedCell(rowIndex, 0);
				}

                //ds_411List.removeRow(i);
			}
		} 

		for(var i=(pgmCnt-1); i>=0; i--){
			var chkYn = ds_411List.getCellData(i, "chk");
			if(chkYn == "1"){
                ds_411List.removeRow(i);
			}
		} 
	}
	// f_GridColHeaderCheckChange('gr_411List');
};

//-------------------------------------------------------------------------
// function name : f_RMove
// function desc : 우이동
//-------------------------------------------------------------------------
scwin.f_RMove = function() {         

	var pgmCnt  = ds_411List.getRowCount();
	var privCnt = ds_451List.getRowCount();

	if(privCnt==0){
		$c.win.alert(scwin.MSG_CM_ERR_007);
		return;
	}else{
		for(var i=0; i<privCnt; i++){
			var chkYn = ds_451List.getCellData(i, "chk");
			var pgmId = ds_451List.getCellData(i, "pgmId");
			var pgmNm = ds_451List.getCellData(i, "pgmNm");

			// if(chkYn == "1" && rowStatus == "C"){
            if(chkYn == "1" ){      
				var addFlag = "A";
				for(var j=0; j<pgmCnt; j++){
					var privPgmId = ds_411List.getCellData(j, "pgmId");
					if(pgmId == privPgmId){
						addFlag = "N";
						break;
					}else{
						continue;
					}
				}

				if(addFlag == "A"){
                    let rowIndex = ds_411List.insertRow();
					ds_411List.setCellData(rowIndex, "pgmId", pgmId); 
					ds_411List.setCellData(rowIndex, "pgmNm", pgmNm); 
					ds_411List.setCellData(rowIndex, "insYn", 0); 

					ds_411List.modifyAllStatus("R");
				}

			}
		}

        for(var i=(privCnt-1); i>=0; i--){
			var chkYn = ds_451List.getCellData(i, "chk");
            var rowStatus = ds_451List.getRowStatus(i);
			if(chkYn == "1"){
                if( rowStatus == "C"){
                    ds_451List.removeRow(i);
                } else {
                    ds_451List.deleteRow(i);
                }    
			}
		}  
	}
};


//-------------------------------------------------------------------------
// 그리드 컬럼헤더 체크 변경
//-------------------------------------------------------------------------
scwin.btn_PrivGrpRetrieve_onclick = function (e) {
    ed_searchPrivGrp.focus();
    scwin.f_Retrieve(0);
};

scwin.btn_ProgramRetrieve_onclick = function (e) {
    scwin.f_Retrieve(1);
};

scwin.sbm_411List_submitdone = function (e) {
    var rowCnt = ds_411List.getRowCount();
    gr_411List_spanTotal.setLabel(rowCnt);
    if (rowCnt == 0) {
        $c.gus.cfAlertMsg(scwin.MSG_CM_ERR_006);
    } else {
		var pgmCnt  = ds_411List.getRowCount();
		var privCnt = ds_451List.getRowCount();

		for(var i=0; i<privCnt; i++){
			var chkYn = ds_451List.getCellData(i, "chk");
			var pgmId = ds_451List.getCellData(i, "pgmId");
			var pgmNm = ds_451List.getCellData(i, "pgmNm");

			var existsYn = "Y";
			for(var j=0; j<pgmCnt; j++){
				var privPgmId = ds_411List.getCellData(j, "pgmId");
				if(pgmId == privPgmId){
					ds_411List.removeRow(j);
					break;
				}else{
					continue;
				}
			}
		}
        ds_411OrgList.setJSON(ds_411List.getAllJSON());
    }
    gr_411List.setFocusedCell(0, 0);    
};

scwin.sbm_415List_submitdone = function (e) {
    var rowCnt = ds_415List.getRowCount();
    gr_415List_spanTotal.setLabel(rowCnt);
    if (rowCnt > 0) {
        ds_415List.sort("privGrpId", 0);
        gr_415List.setFocusedCell(0, 0);
        scwin.f_MainRetrieve(gr_415List.getCellData(0, "privGrpId"));
    } else {
        $c.gus.cfAlertMsg(scwin.MSG_CM_ERR_006);
    }    
};

scwin.sbm_451List_submitdone = async function (e) {
    var rowCnt = ds_451List.getRowCount();
    if(rowCnt == 0) {
        await $c.gus.cfAlertMsg(scwin.MSG_CM_ERR_006);
    } else {
		var pgmCnt  = ds_411List.getRowCount();
		var privCnt = ds_451List.getRowCount();
		// gr_451List.Editable = true;

		for(var i=0; i<privCnt; i++){
			// var chkYn = ds_451List.nameValue(i, "chk");
			var pgmId = ds_451List.getCellData(i, "pgmId");
			var pgmNm = ds_451List.getCellData(i, "pgmNm");

			var existsYn = "Y";
			for(var j=0; j<pgmCnt; j++){
				var privPgmId = ds_411List.getCellData(j, "pgmId");
				if(pgmId == privPgmId){
					ds_411List.removeRow(j);
					break;
				}else{
					continue;
				}
			}
		}
    }
    gr_451List_spanTotal.setLabel(rowCnt);
    gr_451List.setFocusedCell(0, 0);
};

scwin.ds_415List_onrowpositionchange = function (info) {
    var rowIndex = info.newRowIndex;
};

scwin.gr_415List_oncellclick = async function (rowIndex, columnIndex, columnId) {
    ds_415List.getRowStatus(rowIndex)
    //변경한 데이터가 있는지 체크한다. 
    if( ds_415List.getRowStatus(rowIndex) == "U" || ds_451List.getRowStatus(rowIndex) == "U"){

        let confirmResult = await $c.win.confirm(scwin.MSG_CM_CRM_002);
        if (confirmResult) {
            //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
            for(var i=0; i<ds_415List.getRowCount(); i++) {
                var rowJson = ds_415List.getRowJSON(i);
                if(ds_415List.rowStatus=="C" || ds_415List.rowStatus=="U"){
                    if(rowJson.privGrpId.trim()==''){
                        $c.win.alert(scwin.MSG_CM_ERR_001);
                        return;
                    }else if(rowJson.privGrpId.trim().length!=4){
                        $c.win.alert(scwin.MSG_CM_ERR_002);
                        return;
                    }else if(rowJson.privGrpNm.trim()==''){
                        $c.win.alert(scwin.MSG_CM_ERR_003);
                        return;
                    }
                    for(var j=0; j<ds_415List.getRowCount(); j++) {
                        if(j!=i){
                            if( rowJson.privGrpId.trim() == ds_415List.getCellData( j, "privGrpId" ).trim() ){
                                $c.win.alert(scwin.MSG_CM_ERR_004);
                                return;
                            }
                        }	
                    }
                }
            }
            $c.sbm.execute(sbm_save);
        }
    }

    if( ds_415List.getRowStatus(rowIndex) == "C" ) {
        gr_415List.setReadOnly("column", "privGrpId", false);
    } else {
        gr_415List.setReadOnly("column", "privGrpId", true);
        scwin.f_MainRetrieve(gr_415List.getCellData(rowIndex, "privGrpId"));
    }
};



scwin.btn_search1_init_onclick = function (e) {
    $c.gus.cfInitObjects(table1, ["ed_searchPrivGrp"]);
    rd_debis.setSelectedIndex(0);
    if( $p.getAllParameter().paramData.menuInfo.menuId.indexOf("n") > -1){
        rd_debis.setSelectedIndex(1);
    } else {
        rd_debis.setSelectedIndex(0);
    }
};

scwin.btn_search2_init_onclick = function (e) {
    $c.gus.cfInitObjects(table2, null);
};

scwin.f_Filter = function () {

	var pgmCond = lc_pgmCond.getValue();
	var pgmName = ed_pgmName.getValue();
    var rcolumnId = "pgmId";

	switch (pgmCond) {
		case "1":
            rcolumnId = "pgmId";
			break;
		case "2":
            rcolumnId = "pgmNm";
			break;
	}    

    if( pgmCond > 0 ) {
        $c.data.dataListFilter(ds_451List, "LIKE", true, 
            {colId : rcolumnId, func : function(cellData, tmpParam, rowIdx) {
                if(cellData.indexOf(pgmName) > -1){
                    return true;
                }
                return false;   // return이 true인 경우 적용하고 false인 경우 넘김
            } 
            });
    } else {
        ds_451List.removeColumnFilterAll();
    }

};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
	await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    // scwin.f_Retrieve(0);
	var privGrpId = ds_415List.getCellData(ds_415List.getRowPosition(), "privGrpId");//권한그룹조회후 권한그룹별권한조회
	scwin.f_MainRetrieve(privGrpId);	
};

